{
  "name": "Pokemon English Explorer",
  "description": "A cute and interactive Pokemon-themed English word learning game for 3rd graders, featuring multiple mini-games like Emoji Detective, Spelling Bee, and Bubble Pop.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WordItem {
  id: number;
  english: string;
  chinese: string;
  pronunciation: string;
  emoji: string;
  sentence: string;
}

export enum GameType {
  WORD_LIST = 'WORD_LIST',
  EMOJI_DETECTIVE = 'EMOJI_DETECTIVE',
  MATCHING = 'MATCHING',
  SPELLING_BEE = 'SPELLING_BEE',
  FILL_BLANKS = 'FILL_BLANKS',
  BUBBLE_POP = 'BUBBLE_POP',
  RAIN_GAME = 'RAIN_GAME',
  POKEMON_BATTLE = 'POKEMON_BATTLE',
  MEMORY_GAME = 'MEMORY_GAME'
}

export interface Pokemon {
  id: number;
  name: string;
  imageUrl: string;
}

import React, { useState, useEffect } from 'react';
import { VOCABULARY, POKEMON_LIST, getPokemonImageUrl } from './constants';
import { GameType, Pokemon } from './types';
import { LucideHome, LucideBookOpen, LucideGamepad2, LucideCheckCircle, LucideHeart, LucideTrash2 } from 'lucide-react';

// --- Sub-Components ---

const Header = () => (
  <header className="bg-yellow-400 p-4 shadow-md flex justify-between items-center border-b-4 border-yellow-600">
    <div className="flex items-center space-x-2">
      <img src={getPokemonImageUrl(25)} alt="Pikachu" className="w-10 h-10" />
      <h1 className="text-2xl font-title text-white drop-shadow-lg">PokeEng Explorer!</h1>
    </div>
    <div className="text-3xl">✨🌈🎮</div>
  </header>
);

const WordListView = ({ onStart }: { onStart: () => void }) => {
  return (
    <div className="p-4 max-w-4xl mx-auto pb-20">
      <h2 className="text-3xl font-title text-center text-green-600 mb-6">📝 Word List Review</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {VOCABULARY.map((word) => (
          <div key={word.id} className="bg-white p-4 rounded-2xl shadow-sm border-2 border-green-100 flex items-center space-x-4">
            <span className="text-4xl">{word.emoji}</span>
            <div className="flex-1">
              <p className="text-2xl font-bold text-blue-600">{word.english}</p>
              <p className="text-lg text-gray-600 font-semibold">{word.chinese}</p>
              <p className="text-sm text-gray-400 italic">{word.pronunciation}</p>
            </div>
          </div>
        ))}
      </div>
      <button 
        onClick={onStart}
        className="fixed bottom-6 right-6 bg-yellow-400 text-white font-title text-2xl py-4 px-10 rounded-full shadow-xl border-4 border-yellow-600 hover:scale-105 transition-transform"
      >
        GO TO GAMES! 🚀
      </button>
    </div>
  );
};

// --- Games Components ---

const EmojiDetective = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const targetWord = VOCABULARY[currentIdx];

  useEffect(() => {
    const opts = [targetWord.english];
    while (opts.length < 4) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
      if (!opts.includes(rand)) opts.push(rand);
    }
    setOptions(opts.sort(() => Math.random() - 0.5));
  }, [currentIdx]);

  const handleSelect = (choice: string) => {
    if (choice === targetWord.english) {
      if (currentIdx + 1 < VOCABULARY.length) {
        setCurrentIdx(currentIdx + 1);
      } else {
        onWin();
      }
    } else {
      alert("Oops! Try again! ❌");
    }
  };

  return (
    <div className="flex flex-col items-center p-8 bg-blue-50 min-h-[60vh] rounded-3xl">
      <img src={getPokemonImageUrl(54)} className="w-32 h-32 pokemon-float" alt="Psyduck" />
      <h3 className="text-4xl font-title text-blue-800 mb-8">Who matches this emoji?</h3>
      <div className="text-9xl mb-12 drop-shadow-xl">{targetWord.emoji}</div>
      <div className="grid grid-cols-2 gap-4 w-full max-w-md">
        {options.map(opt => (
          <button 
            key={opt}
            onClick={() => handleSelect(opt)}
            className="bg-white p-6 rounded-2xl border-4 border-blue-200 text-xl font-bold text-blue-600 hover:bg-blue-100 transition-colors shadow-lg"
          >
            {opt}
          </button>
        ))}
      </div>
      <div className="mt-8 text-blue-400 font-bold">Progress: {currentIdx + 1} / {VOCABULARY.length}</div>
    </div>
  );
};

const SpellingBee = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const targetChars = targetWord.english.toLowerCase().split("");
  const [guess, setGuess] = useState<string[]>([]);
  const [shuffledLetters, setShuffledLetters] = useState<string[]>([]);

  useEffect(() => {
    const chars = [...targetChars].filter(c => c !== " " && c !== "-");
    setShuffledLetters(chars.sort(() => Math.random() - 0.5));
    setGuess([]);
  }, [currentIdx]);

  const handleAddLetter = (char: string) => {
    const newGuess = [...guess, char];
    setGuess(newGuess);

    // Auto-spacing and special chars are handled by the comparison logic
    const sanitizedTarget = targetWord.english.toLowerCase().replace(/[\s-]/g, "");
    if (newGuess.join("") === sanitizedTarget) {
      if (currentIdx + 1 < VOCABULARY.length) {
        setCurrentIdx(currentIdx + 1);
      } else {
        onWin();
      }
    }
  };

  const removeLast = () => setGuess(guess.slice(0, -1));

  return (
    <div className="flex flex-col items-center p-8 bg-yellow-50 min-h-[60vh] rounded-3xl">
      <img src={getPokemonImageUrl(25)} className="w-32 h-32 pokemon-float" alt="Pikachu" />
      <h3 className="text-3xl font-title text-yellow-800 mb-4">{targetWord.chinese}</h3>
      <div className="text-6xl mb-8">{targetWord.emoji}</div>

      <div className="flex flex-wrap justify-center gap-2 mb-10 h-16">
        {targetWord.english.split("").map((c, i) => {
          const isSpecial = c === " " || c === "-";
          // Calculate current letter index for matching non-special chars
          const nonSpecialSoFar = targetWord.english.slice(0, i+1).replace(/[\s-]/g, "").length;
          const letter = isSpecial ? c : (guess[nonSpecialSoFar-1] || "_");
          return (
            <span key={i} className={`text-4xl font-bold ${isSpecial ? 'mx-2 text-gray-300' : 'border-b-4 border-yellow-400 w-12 text-center'}`}>
              {letter}
            </span>
          );
        })}
      </div>

      <div className="flex flex-wrap justify-center gap-3">
        {shuffledLetters.map((l, i) => (
          <button 
            key={i}
            onClick={() => handleAddLetter(l)}
            className="bg-white w-14 h-14 rounded-xl border-2 border-yellow-400 text-2xl font-bold shadow-md hover:bg-yellow-100"
          >
            {l}
          </button>
        ))}
        <button onClick={removeLast} className="bg-red-400 text-white p-3 rounded-xl shadow-md"><LucideTrash2 /></button>
      </div>
    </div>
  );
};

const BubblePop = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const [caught, setCaught] = useState<number[]>([]);
  const targetWord = VOCABULARY[currentIdx];

  useEffect(() => {
    const opts = [targetWord.english];
    while (opts.length < 6) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
      if (!opts.includes(rand)) opts.push(rand);
    }
    setOptions(opts.sort(() => Math.random() - 0.5));
  }, [currentIdx]);

  const handlePop = (word: string) => {
    if (word === targetWord.english) {
      setCaught([...caught, POKEMON_LIST[currentIdx % POKEMON_LIST.length].id]);
      if (currentIdx + 1 < VOCABULARY.length) {
        setCurrentIdx(currentIdx + 1);
      } else {
        onWin();
      }
    }
  };

  return (
    <div className="relative min-h-[70vh] bg-blue-900 rounded-3xl overflow-hidden border-8 border-blue-400 p-8 text-white">
      {/* Background Decor */}
      <div className="absolute top-4 left-4 text-4xl opacity-50 bubble-float">🐙</div>
      <div className="absolute bottom-4 right-4 text-4xl opacity-50 bubble-float">🐠</div>
      <div className="absolute top-1/2 left-10 text-4xl opacity-30 bubble-float">🦐</div>

      <div className="relative z-10 flex flex-col items-center">
        <h3 className="text-3xl font-title mb-2 text-cyan-300">Bubble Pop! 🫧</h3>
        <p className="text-4xl font-bold mb-8">Pick English for: {targetWord.chinese}</p>

        <div className="grid grid-cols-3 grid-rows-2 gap-8 mb-12">
          {options.map((opt, i) => (
            <button
              key={i}
              onClick={() => handlePop(opt)}
              className="w-36 h-36 rounded-full bg-blue-400/50 border-4 border-white flex items-center justify-center p-4 text-center font-bold text-lg hover:scale-110 transition-transform shadow-[0_0_20px_rgba(255,255,255,0.4)]"
            >
              {opt}
            </button>
          ))}
        </div>

        <div className="flex flex-wrap justify-center gap-4 bg-white/10 p-4 rounded-2xl w-full">
           <p className="w-full text-center text-sm font-title uppercase tracking-widest text-blue-200">Shell Collection 🐚</p>
           {caught.map((pkId, idx) => (
             <div key={idx} className="bg-white/20 p-2 rounded-full relative">
               <img src={getPokemonImageUrl(pkId)} className="w-12 h-12" alt="caught" />
               <span className="absolute -bottom-1 -right-1 text-xs">🐚</span>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

const RainGame = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const [drops, setDrops] = useState<{ id: number, text: string, top: number, left: number }[]>([]);

  useEffect(() => {
    const generateDrops = () => {
      const newDrops = [];
      const usedWords = [targetWord.english];
      for (let i = 0; i < 5; i++) {
        let rand;
        do {
          rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
        } while (usedWords.includes(rand));
        usedWords.push(rand);
      }

      for (let i = 0; i < 6; i++) {
        newDrops.push({
          id: i,
          text: usedWords[i],
          top: Math.random() * 60 + 20, // fixed position as requested "固定在那" effectively
          left: (i % 3) * 30 + 10
        });
      }
      setDrops(newDrops.sort(() => Math.random() - 0.5));
    };
    generateDrops();
  }, [currentIdx]);

  const handleDropClick = (text: string) => {
    if (text === targetWord.english) {
      if (currentIdx + 1 < VOCABULARY.length) {
        setCurrentIdx(currentIdx + 1);
      } else {
        onWin();
      }
    }
  };

  return (
    <div className="relative min-h-[60vh] bg-blue-100 rounded-3xl overflow-hidden p-8 flex flex-col items-center">
      <div className="mb-4 text-center">
        <h3 className="text-4xl font-title text-blue-700">Rain Game 🌧️</h3>
        <p className="text-2xl font-bold bg-white px-6 py-2 rounded-full border-2 border-blue-400 mt-2">
          {targetWord.chinese}
        </p>
      </div>

      <div className="relative w-full h-[400px]">
        {drops.map(drop => (
          <button
            key={drop.id}
            onClick={() => handleDropClick(drop.text)}
            style={{ top: `${drop.top}%`, left: `${drop.left}%` }}
            className="absolute bg-blue-400 text-white px-6 py-4 rounded-full shadow-lg font-bold border-2 border-white hover:bg-blue-600 transition-colors"
          >
            💧 {drop.text}
          </button>
        ))}
      </div>

      <div className="absolute bottom-4 left-4 flex items-end">
        <img src={getPokemonImageUrl(186)} className="w-32 h-32 pokemon-float" alt="Politoed" />
        <div className="bg-white p-3 rounded-2xl rounded-bl-none border-2 border-blue-300 ml-2 mb-10">
          <p className="text-sm font-bold">Catch the right drop! Ribbit!</p>
        </div>
      </div>
    </div>
  );
};

const PokemonBattle = ({ onWin }: { onWin: () => void }) => {
  const [enemyHp, setEnemyHp] = useState(100);
  const [playerHp, setPlayerHp] = useState(100);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const targetWord = VOCABULARY[currentIdx];

  useEffect(() => {
    const opts = [targetWord.english];
    while (opts.length < 4) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
      if (!opts.includes(rand)) opts.push(rand);
    }
    setOptions(opts.sort(() => Math.random() - 0.5));
  }, [currentIdx]);

  const handleAttack = (choice: string) => {
    if (choice === targetWord.english) {
      setEnemyHp(prev => Math.max(0, prev - 20));
      if (enemyHp <= 20) onWin();
      else setCurrentIdx((currentIdx + 1) % VOCABULARY.length);
    } else {
      setPlayerHp(prev => Math.max(0, prev - 10));
    }
  };

  return (
    <div className="bg-gradient-to-b from-green-300 to-green-100 rounded-3xl p-8 min-h-[60vh] flex flex-col justify-between">
      <div className="flex justify-between items-start mb-12">
        <div className="bg-white p-4 rounded-xl shadow-md border-2 border-gray-200 w-48">
          <p className="font-title text-sm">MEWTWO 😈</p>
          <div className="w-full bg-gray-200 h-4 rounded-full mt-2 overflow-hidden">
            <div className={`h-full transition-all duration-500 ${enemyHp > 50 ? 'bg-green-500' : enemyHp > 20 ? 'bg-yellow-400' : 'bg-red-500'}`} style={{ width: `${enemyHp}%` }}></div>
          </div>
          <p className="text-xs text-right mt-1 font-bold">{enemyHp}/100 HP</p>
        </div>
        <img src={getPokemonImageUrl(150)} className="w-40 h-40 pokemon-float" alt="Mewtwo" />
      </div>

      <div className="flex justify-center mb-8">
        <div className="bg-white/80 backdrop-blur-sm p-6 rounded-2xl border-4 border-yellow-400 w-full max-w-lg text-center">
          <p className="text-xl font-bold mb-4">{targetWord.sentence.replace('_____', '______')}</p>
          <div className="grid grid-cols-2 gap-4">
            {options.map(opt => (
              <button
                key={opt}
                onClick={() => handleAttack(opt)}
                className="bg-yellow-400 text-white font-bold py-3 rounded-xl hover:bg-yellow-500 shadow-md"
              >
                {opt}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex justify-between items-end">
        <img src={getPokemonImageUrl(6)} className="w-40 h-40 pokemon-float" alt="Charizard" style={{ transform: 'scaleX(-1)' }} />
        <div className="bg-white p-4 rounded-xl shadow-md border-2 border-gray-200 w-48">
          <p className="font-title text-sm">CHARIZARD 🔥</p>
          <div className="w-full bg-gray-200 h-4 rounded-full mt-2 overflow-hidden">
            <div className={`h-full transition-all duration-500 ${playerHp > 50 ? 'bg-green-500' : playerHp > 20 ? 'bg-yellow-400' : 'bg-red-500'}`} style={{ width: `${playerHp}%` }}></div>
          </div>
          <p className="text-xs text-right mt-1 font-bold">{playerHp}/100 HP</p>
        </div>
      </div>
    </div>
  );
};

// --- Main App ---

export default function App() {
  const [view, setView] = useState<GameType>(GameType.WORD_LIST);
  const [caughtPokemon, setCaughtPokemon] = useState<Pokemon[]>([]);
  const [showReward, setShowReward] = useState(false);

  const handleWin = () => {
    const newPk = POKEMON_LIST[Math.floor(Math.random() * POKEMON_LIST.length)];
    setCaughtPokemon([...caughtPokemon, newPk]);
    setShowReward(true);
  };

  const closeReward = () => {
    setShowReward(false);
    setView(GameType.WORD_LIST); // Go back to main after a win
  };

  return (
    <div className="min-h-screen bg-green-50">
      <Header />

      <main className="container mx-auto py-8 px-4">
        {view === GameType.WORD_LIST && <WordListView onStart={() => setView(GameType.EMOJI_DETECTIVE)} />}

        {view === GameType.EMOJI_DETECTIVE && <EmojiDetective onWin={handleWin} />}
        {view === GameType.SPELLING_BEE && <SpellingBee onWin={handleWin} />}
        {view === GameType.BUBBLE_POP && <BubblePop onWin={handleWin} />}
        {view === GameType.RAIN_GAME && <RainGame onWin={handleWin} />}
        {view === GameType.POKEMON_BATTLE && <PokemonBattle onWin={handleWin} />}

        {/* Game Navigation */}
        {view !== GameType.WORD_LIST && (
          <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md p-4 flex justify-around border-t-2 border-yellow-200 z-40">
            <button onClick={() => setView(GameType.WORD_LIST)} className="flex flex-col items-center text-gray-500 hover:text-yellow-600">
              <LucideHome size={24} />
              <span className="text-xs">Home</span>
            </button>
            <button onClick={() => setView(GameType.EMOJI_DETECTIVE)} className="flex flex-col items-center text-gray-500 hover:text-blue-600">
              <LucideGamepad2 size={24} />
              <span className="text-xs">Detective</span>
            </button>
            <button onClick={() => setView(GameType.SPELLING_BEE)} className="flex flex-col items-center text-gray-500 hover:text-yellow-600">
              <LucideGamepad2 size={24} />
              <span className="text-xs">Spelling</span>
            </button>
            <button onClick={() => setView(GameType.BUBBLE_POP)} className="flex flex-col items-center text-gray-500 hover:text-cyan-600">
              <LucideGamepad2 size={24} />
              <span className="text-xs">Bubbles</span>
            </button>
            <button onClick={() => setView(GameType.RAIN_GAME)} className="flex flex-col items-center text-gray-500 hover:text-blue-600">
              <LucideGamepad2 size={24} />
              <span className="text-xs">Rain</span>
            </button>
            <button onClick={() => setView(GameType.POKEMON_BATTLE)} className="flex flex-col items-center text-gray-500 hover:text-red-600">
              <LucideGamepad2 size={24} />
              <span className="text-xs">Battle</span>
            </button>
          </nav>
        )}
      </main>

      {/* Collection Sidebar / Bottom Bar */}
      {caughtPokemon.length > 0 && (
        <div className="fixed top-20 right-4 flex flex-col items-center space-y-2 z-30">
          <div className="bg-white p-3 rounded-full shadow-lg border-2 border-yellow-400">
            <p className="text-xs font-bold text-yellow-600">Caught: {caughtPokemon.length}</p>
          </div>
        </div>
      )}

      {/* Reward Modal */}
      {showReward && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-6 backdrop-blur-sm">
          <div className="bg-white rounded-3xl p-10 max-w-sm w-full text-center shadow-[0_0_50px_rgba(255,255,255,0.5)] border-8 border-yellow-400">
            <h2 className="text-4xl font-title text-yellow-600 mb-4">GOTCHA! 🎉</h2>
            <img 
              src={caughtPokemon[caughtPokemon.length - 1].imageUrl} 
              className="w-48 h-48 mx-auto pokemon-float mb-4" 
              alt="Caught Pokemon" 
            />
            <p className="text-2xl font-bold mb-8 italic">You caught a {caughtPokemon[caughtPokemon.length - 1].name}!</p>
            <button 
              onClick={closeReward}
              className="bg-green-500 text-white font-title text-xl py-4 px-10 rounded-full hover:bg-green-600 transition-colors w-full"
            >
              KEEP PLAYING! 🌟
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { VOCABULARY, POKEMON_LIST, getPokemonImageUrl } from './constants';
import { GameType, Pokemon, WordItem } from './types';
import { LucideHome, LucideGamepad2, LucideTrash2, LucideBrain, LucideRefreshCcw, LucideTrophy, LucideFlame } from 'lucide-react';

// --- Global Header ---
const Header = () => (
  <header className="bg-yellow-400 p-4 shadow-md flex justify-between items-center border-b-4 border-yellow-600 sticky top-0 z-50">
    <div className="flex items-center space-x-2">
      <img src={getPokemonImageUrl(25)} alt="Pikachu" className="w-10 h-10" />
      <h1 className="text-2xl font-title text-white drop-shadow-lg">PokeEng Explorer!</h1>
    </div>
    <div className="flex space-x-2">
      <span className="text-2xl">✨</span>
      <span className="text-2xl">🌈</span>
    </div>
  </header>
);

// --- Review View ---
const WordListView = ({ onStart }: { onStart: () => void }) => {
  return (
    <div className="p-4 max-w-4xl mx-auto pb-24">
      <div className="bg-white rounded-3xl p-6 shadow-xl border-4 border-green-400 mb-8 flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-title text-green-600">📝 Diary Review</h2>
          <p className="text-gray-500 font-bold italic">Let's study before we play! 📖</p>
        </div>
        <img src={getPokemonImageUrl(1)} className="w-24 h-24" alt="Bulbasaur" />
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {VOCABULARY.map((word) => (
          <div key={word.id} className="bg-white p-6 rounded-2xl shadow-sm border-2 border-green-100 flex items-center space-x-4 hover:border-green-400 transition-all">
            <span className="text-5xl">{word.emoji}</span>
            <div className="flex-1">
              <p className="text-2xl font-bold text-blue-600 tracking-wide">{word.english}</p>
              <p className="text-xl text-gray-700 font-bold">{word.chinese}</p>
              <p className="text-sm text-gray-400 italic font-medium">{word.pronunciation}</p>
            </div>
          </div>
        ))}
      </div>
      <button 
        onClick={onStart}
        className="fixed bottom-24 right-6 bg-yellow-400 text-white font-title text-2xl py-5 px-12 rounded-full shadow-2xl border-4 border-yellow-600 hover:scale-110 transition-transform active:scale-95 flex items-center gap-3"
      >
        LET'S PLAY! <LucideGamepad2 />
      </button>
    </div>
