// 6. Word Search (Lucario)
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx].english.toLowerCase().replace(/[^a-z]/g, "");
  const [grid, setGrid] = useState<string[][]>([]);
  const [selected, setSelected] = useState<[number, number][]>([]);

  useEffect(() => {
    const size = 10;
    const newGrid = Array(size).fill(0).map(() => Array(size).fill(0).map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));

    // Simple horizontal placement
    const row = Math.floor(Math.random() * size);
    const colStart = Math.floor(Math.random() * (size - targetWord.length));
    for (let i = 0; i < targetWord.length; i++) {
      newGrid[row][colStart + i] = targetWord[i];
    }
    setGrid(newGrid);
    setSelected([]);
  }, [currentIdx, targetWord]);

  const handleCell = (r: number, c: number) => {
    const newSelected = [...selected, [r, c] as [number, number]];
    setSelected(newSelected);

    const currentString = newSelected.map(([r, c]) => grid[r][c]).join("");
    if (currentString === targetWord) {
      if (currentIdx + 1 < VOCABULARY.length) setCurrentIdx(currentIdx + 1);
      else onWin();
    } else if (currentString.length >= targetWord.length) {
      setSelected([]);
    }
  };

  return (
    <div className="p-8 bg-indigo-50 rounded-3xl border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex items-center gap-4 mb-6">
        <img src={getPokemonImageUrl(448)} className="w-24 h-24" alt="Lucario" />
        <div>
          <h3 className="text-3xl font-title text-indigo-800">Word Search Puzzle</h3>
          <p className="text-xl font-bold text-indigo-600 underline">Find: {VOCABULARY[currentIdx].english}</p>
        </div>
      </div>
      <div className="grid grid-cols-10 gap-1 bg-white p-3 rounded-2xl shadow-xl border-4 border-indigo-100">
        {grid.map((row, r) => row.map((char, c) => {
          const isSelected = selected.some(([sr, sc]) => sr === r && sc === c);
          return (
            <button key={`${r}-${c}`} onClick={() => handleCell(r, c)} className={`w-8 h-8 sm:w-10 sm:h-10 text-xl font-bold rounded flex items-center justify-center transition-colors ${isSelected ? 'bg-indigo-500 text-white' : 'hover:bg-indigo-100'}`}>
              {char.toUpperCase()}
            </button>
          );
        }))}
      </div>
      <button onClick={() => setSelected([])} className="mt-6 flex items-center gap-2 bg-indigo-200 text-indigo-800 px-6 py-2 rounded-full font-bold"><LucideRefreshCcw size={18} /> Clear Selection</button>
    </div>
  );
};

