      <div className="bg-white p-8 rounded-full shadow-lg text-9xl mb-12 border-8 border-blue-100">{targetWord.emoji}</div>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full max-w-xl">
        {options.map(opt => (
          <button key={opt} onClick={() => handleSelect(opt)} className="bg-white p-5 rounded-2xl border-4 border-blue-200 text-2xl font-bold text-blue-600 hover:bg-blue-100 hover:scale-105 transition-all shadow-md">{opt}</button>
        ))}
      </div>
      <p className="mt-8 font-bold text-blue-400">Step {currentIdx + 1} of {VOCABULARY.length}</p>
    </div>
  );
};

// 2. Matching Game (Eevee)
const MatchingGame = ({ onWin }: { onWin: () => void }) => {
  const [pairs, setPairs] = useState<{ en: string; cn: string }[]>([]);
  const [selectedEn, setSelectedEn] = useState<string | null>(null);
  const [selectedCn, setSelectedCn] = useState<string | null>(null);
  const [solved, setSolved] = useState<string[]>([]);

  useEffect(() => {
    const subset = [...VOCABULARY].sort(() => Math.random() - 0.5).slice(0, 5);
    setPairs(subset.map(w => ({ en: w.english, cn: w.chinese })));
  }, []);

  const enList = useMemo(() => [...pairs].sort((a,b) => a.en.localeCompare(b.en)), [pairs]);
  const cnList = useMemo(() => [...pairs].sort(() => Math.random() - 0.5), [pairs]);

  const handleSelect = (val: string, type: 'en' | 'cn') => {
    if (type === 'en') setSelectedEn(val);
    else setSelectedCn(val);
  };

  useEffect(() => {
    if (selectedEn && selectedCn) {
      const match = pairs.find(p => p.en === selectedEn && p.cn === selectedCn);
      if (match) {
        setSolved([...solved, selectedEn]);
        if (solved.length + 1 === pairs.length) onWin();
      }
      setSelectedEn(null);
      setSelectedCn(null);
    }
  }, [selectedEn, selectedCn, pairs, solved]);

  return (
    <div className="p-8 bg-pink-50 rounded-3xl border-4 border-pink-200">
      <div className="flex items-center justify-center mb-8 gap-4">
        <img src={getPokemonImageUrl(133)} className="w-24 h-24 pokemon-float" alt="Eevee" />
        <h3 className="text-3xl font-title text-pink-700">English - Chinese Match</h3>
      </div>
      <div className="grid grid-cols-2 gap-12 max-w-2xl mx-auto">
        <div className="flex flex-col gap-4">
          {enList.map(item => (
            <button
              key={item.en}
              disabled={solved.includes(item.en)}
              onClick={() => handleSelect(item.en, 'en')}
              className={`p-4 rounded-xl text-xl font-bold border-4 transition-all ${solved.includes(item.en) ? 'bg-gray-100 border-gray-100 text-gray-300' : selectedEn === item.en ? 'bg-pink-400 border-pink-600 text-white' : 'bg-white border-pink-200 text-pink-600 shadow-md'}`}
            >
              {item.en}
            </button>
          ))}
        </div>
        <div className="flex flex-col gap-4">
          {cnList.map(item => (
            <button
              key={item.cn}
              disabled={solved.includes(item.en)}
              onClick={() => handleSelect(item.cn, 'cn')}
              className={`p-4 rounded-xl text-xl font-bold border-4 transition-all ${solved.includes(item.en) ? 'bg-gray-100 border-gray-100 text-gray-300' : selectedCn === item.cn ? 'bg-blue-400 border-blue-600 text-white' : 'bg-white border-blue-200 text-blue-600 shadow-md'}`}
            >
              {item.cn}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

// 3. Spelling Bee (Pikachu)
const SpellingBee = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const [guess, setGuess] = useState<string[]>([]);

  const displayParts = targetWord.english.toLowerCase().split("");
  const lettersOnly = targetWord.english.toLowerCase().replace(/[^a-z]/g, "").split("");
  const [pool, setPool] = useState<string[]>([]);

  useEffect(() => {
    setPool([...lettersOnly].sort(() => Math.random() - 0.5));
    setGuess([]);
  }, [currentIdx]);

  const handleLetter = (l: string) => {
    const newGuess = [...guess, l];
    setGuess(newGuess);
    if (newGuess.join("") === lettersOnly.join("")) {
      if (currentIdx + 1 < VOCABULARY.length) setCurrentIdx(currentIdx + 1);
      else onWin();
    }
  };

  const undo = (char: string, index: number) => {
    if (index === guess.length - 1) setGuess(guess.slice(0, -1));
  };

  let charPointer = 0;

  return (
    <div className="p-8 bg-yellow-50 rounded-3xl border-4 border-yellow-200 min-h-[60vh] flex flex-col items-center">
      <img src={getPokemonImageUrl(25)} className="w-32 h-32 pokemon-float mb-4" alt="Pikachu" />
      <h3 className="text-3xl font-title text-yellow-800 mb-2">{targetWord.chinese} {targetWord.emoji}</h3>

      <div className="flex flex-wrap justify-center gap-2 my-12 min-h-20">
        {displayParts.map((char, i) => {
          const isLetter = /[a-z]/.test(char);
          if (!isLetter) return <span key={i} className="text-4xl text-gray-300 mx-1">{char === " " ? "  " : char}</span>;
          const currentGuessChar = guess[charPointer];
          const isCorrect = currentGuessChar === char;
          const content = currentGuessChar || "_";
          const pIdx = charPointer;
          charPointer++;
          return (
            <button key={i} onClick={() => undo(content, pIdx)} className={`text-4xl font-bold w-12 border-b-4 pb-2 text-center transition-all ${currentGuessChar ? (isCorrect ? 'text-green-500 border-green-500' : 'text-red-500 border-red-500') : 'border-yellow-300 text-yellow-300'}`}>
              {content}
            </button>
          );
        })}
      </div>

      <div className="grid grid-cols-5 gap-3 max-w-md">
        {pool.map((l, i) => (
          <button key={i} onClick={() => handleLetter(l)} className="bg-white w-14 h-14 rounded-2xl border-4 border-yellow-200 text-2xl font-bold shadow-md hover:bg-yellow-100 active:translate-y-1 transition-all">
            {l}
          </button>
        ))}
        <button onClick={() => setGuess(guess.slice(0, -1))} className="bg-red-400 text-white w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg"><LucideTrash2 /></button>
      </div>
    </div>
  );
};

