};

// 7. Pokemon Battle (Charizard)
const PokemonBattle = ({ onWin }: { onWin: () => void }) => {
  const [enemyHp, setEnemyHp] = useState(100);
  const [playerHp, setPlayerHp] = useState(100);
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const options = useMemo(() => {
    const opts = [targetWord.english];
    while (opts.length < 4) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
      if (!opts.includes(rand)) opts.push(rand);
    }
    return opts.sort(() => Math.random() - 0.5);
  }, [currentIdx]);

  const attack = (choice: string) => {
    if (choice === targetWord.english) {
      setEnemyHp(h => Math.max(0, h - 25));
      if (enemyHp <= 25) onWin();
      else setCurrentIdx((currentIdx + 1) % VOCABULARY.length);
    } else {
      setPlayerHp(h => Math.max(0, h - 10));
    }
  };

  const getHpColor = (hp: number) => hp > 50 ? 'bg-green-500' : hp > 20 ? 'bg-yellow-400' : 'bg-red-500';

  return (
    <div className="p-8 bg-gradient-to-b from-orange-100 to-red-50 rounded-3xl border-4 border-orange-200 min-h-[65vh] flex flex-col justify-between overflow-hidden">
      <div className="flex justify-between">
        <div className="bg-white/80 p-3 rounded-xl border-2 border-gray-300 w-44 shadow-md">
          <p className="font-title text-sm flex items-center gap-1">MEWTWO 😈 <span className="text-xs text-gray-400 font-sans">Lv. 99</span></p>
          <div className="h-3 w-full bg-gray-200 rounded-full mt-2"><div className={`h-full transition-all duration-700 ${getHpColor(enemyHp)}`} style={{ width: `${enemyHp}%` }}></div></div>
        </div>
        <img src={getPokemonImageUrl(150)} className="w-40 h-40 pokemon-float" alt="Mewtwo" />
      </div>

      <div className="bg-white/90 p-6 rounded-3xl border-4 border-orange-300 w-full max-w-xl mx-auto text-center shadow-xl">
        <p className="text-2xl font-bold mb-6 italic leading-relaxed">{targetWord.sentence.replace('_____', '______')}</p>
        <div className="grid grid-cols-2 gap-4">
          {options.map(opt => (
            <button key={opt} onClick={() => attack(opt)} className="bg-orange-400 text-white p-4 rounded-xl font-title hover:bg-orange-500 active:scale-95 shadow-lg border-b-4 border-orange-600 transition-all">{opt}</button>
          ))}
        </div>
      </div>

      <div className="flex justify-between items-end">
        <img src={getPokemonImageUrl(6)} className="w-44 h-44 pokemon-float" alt="Charizard" style={{ transform: 'scaleX(-1)' }} />
        <div className="bg-white/80 p-3 rounded-xl border-2 border-gray-300 w-44 shadow-md">
          <p className="font-title text-sm flex items-center gap-1">CHARIZARD 🔥 <span className="text-xs text-gray-400 font-sans">Lv. 70</span></p>
          <div className="h-3 w-full bg-gray-200 rounded-full mt-2"><div className={`h-full transition-all duration-700 ${getHpColor(playerHp)}`} style={{ width: `${playerHp}%` }}></div></div>
        </div>
      </div>
    </div>
  );
};

// 8. Rain Game (Politoed)
const RainGame = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const drops = useMemo(() => {
    const list = [targetWord.english];
    while (list.length < 6) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
      if (!list.includes(rand)) list.push(rand);
    }
    return list.sort(() => Math.random() - 0.5).map((t, i) => ({ text: t, left: (i % 3) * 30 + 10, top: Math.floor(i / 3) * 30 + 15 }));
  }, [currentIdx]);

  const handleDrop = (text: string) => {
    if (text === targetWord.english) {
      if (currentIdx + 1 < VOCABULARY.length) setCurrentIdx(currentIdx + 1);
      else onWin();
    }
  };

  return (
    <div className="p-8 bg-blue-100 rounded-3xl border-4 border-blue-300 min-h-[60vh] relative overflow-hidden flex flex-col items-center">
      <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/rain.png')] opacity-30 pointer-events-none"></div>
      <h3 className="text-3xl font-title text-blue-800 mb-4 z-10">Rain Game 🌧️</h3>
      <div className="bg-white px-8 py-3 rounded-full border-4 border-blue-400 text-3xl font-bold shadow-xl z-10">{targetWord.chinese}</div>

      <div className="flex-1 w-full relative mt-10">
        {drops.map((d, i) => (
          <button key={i} onClick={() => handleDrop(d.text)} style={{ left: `${d.left}%`, top: `${d.top}%` }} className="absolute bg-blue-500/80 text-white p-5 rounded-full font-bold shadow-lg border-2 border-white hover:scale-110 active:scale-95 transition-all text-xl bubble-float">
            💧 {d.text}
          </button>
        ))}
      </div>

      <div className="absolute bottom-4 left-4 flex items-end">
        <img src={getPokemonImageUrl(186)} className="w-32 h-32 pokemon-float" alt="Politoed" />
        <div className="bg-white p-4 rounded-3xl rounded-bl-none border-2 border-blue-400 shadow-md ml-2 mb-8 max-w-[150px]">
          <p className="text-sm font-bold leading-tight">Catch the right word drop! Ribbit! 🐸</p>
        </div>
      </div>
    </div>
  );
};

// 9. Memory Game (Mew)
const MemoryGame = ({ onWin }: { onWin: () => void }) => {
  const [phase, setPhase] = useState<'study' | 'guess'>('study');
  const [words, setWords] = useState<WordItem[]>([]);
  const [missingWord, setMissingWord] = useState<WordItem | null>(null);
  const [timer, setTimer] = useState(10);

  const setupRound = () => {
    const subset = [...VOCABULARY].sort(() => Math.random() - 0.5).slice(0, 8);
    setWords(subset);
    setMissingWord(subset[Math.floor(Math.random() * subset.length)]);
    setPhase('study');
    setTimer(10);
  };

  useEffect(() => { setupRound(); }, []);

  useEffect(() => {
    if (phase === 'study' && timer > 0) {
      const t = setTimeout(() => setTimer(timer - 1), 1000);
      return () => clearTimeout(t);
    } else if (phase === 'study' && timer === 0) {
      setPhase('guess');
    }
  }, [timer, phase]);

  const handleGuess = (id: number) => {
    if (id === missingWord?.id) onWin();
    else setupRound();
  };

  return (
    <div className="p-8 bg-purple-50 rounded-3xl border-4 border-purple-200 min-h-[60vh] flex flex-col items-center">
      <img src={getPokemonImageUrl(151)} className="w-32 h-32 pokemon-float mb-4" alt="Mew" />
      {phase === 'study' ? (
        <>
          <h3 className="text-3xl font-title text-purple-700 mb-2">Memorize these words!</h3>
          <div className="text-5xl font-bold text-red-500 mb-8 flex items-center gap-2"><LucideBrain /> {timer}s</div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {words.map(w => (
              <div key={w.id} className="bg-white p-4 rounded-xl shadow-md border-2 border-purple-100 flex flex-col items-center">
                <span className="text-3xl mb-1">{w.emoji}</span>
                <p className="text-sm font-bold text-center">{w.english}</p>
              </div>
            ))}
          </div>
        </>
      ) : (
        <>
          <h3 className="text-3xl font-title text-purple-700 mb-8">Which word is missing? 🤔</h3>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-12 opacity-50">
            {words.filter(w => w.id !== missingWord?.id).map(w => (
              <div key={w.id} className="bg-white p-4 rounded-xl shadow-md border-2 border-purple-100 flex flex-col items-center">
                <span className="text-3xl mb-1">{w.emoji}</span>
                <p className="text-sm font-bold text-center">{w.english}</p>
              </div>
            ))}
            <div className="bg-purple-200 p-4 rounded-xl shadow-inner border-2 border-dashed border-purple-400 flex flex-col items-center justify-center">
              <span className="text-3xl">❓</span>
            </div>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 w-full">
            {words.sort(() => Math.random() - 0.5).map(w => (
              <button key={w.id} onClick={() => handleGuess(w.id)} className="bg-white p-3 rounded-xl border-2 border-purple-300 font-bold hover:bg-purple-100 shadow-sm">{w.english}</button>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

