        <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md shadow-[0_-4px_10px_rgba(0,0,0,0.05)] border-t-4 border-yellow-200 p-2 z-40 overflow-x-auto">
