            <NavBtn icon="🖊️" label="Fill" active={view === GameType.FILL_BLANKS} onClick={() => setView(GameType.FILL_BLANKS)} color="text-green-600" />
            <NavBtn icon="🫧" label="Bubble" active={view === GameType.BUBBLE_POP} onClick={() => setView(GameType.BUBBLE_POP)} color="text-cyan-600" />
            <NavBtn icon="🔍" label="Search" active={view === GameType.WORD_SEARCH} onClick={() => setView(GameType.WORD_SEARCH)} color="text-indigo-600" />
            <NavBtn icon="🔥" label="Battle" active={view === GameType.POKEMON_BATTLE} onClick={() => setView(GameType.POKEMON_BATTLE)} color="text-orange-600" />
