            <NavBtn icon="🧠" label="Memory" active={view === GameType.MEMORY_GAME} onClick={() => setView(GameType.MEMORY_GAME)} color="text-purple-600" />
          </div>
        </nav>
      )}

      {/* Reward Popup */}
      {reward && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center p-4 z-[100] backdrop-blur-sm animate-in fade-in zoom-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 max-w-sm w-full text-center shadow-[0_0_80px_rgba(255,255,255,0.4)] border-[12px] border-yellow-400">
            <div className="relative mb-6">
              <div className="absolute inset-0 bg-yellow-100 rounded-full scale-110 blur-xl opacity-50"></div>
              <img src={reward.imageUrl} className="w-56 h-56 mx-auto relative z-10 pokemon-float" alt="Pokemon" />
            </div>
            <h2 className="text-4xl font-title text-yellow-600 mb-2">AMAZING! 🎊</h2>
            <p className="text-2xl font-bold text-gray-700 italic mb-8 uppercase tracking-widest">You caught a {reward.name}!</p>
