function NavBtn({ icon, label, active, onClick, color }: { icon: any, label: string, active: boolean, onClick: () => void, color: string }) {
  return (
    <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-xl transition-all ${active ? 'bg-yellow-100 scale-110' : 'opacity-60 grayscale-[50%] hover:opacity-100'}`}>
      <span className={`text-2xl ${active ? color : 'text-gray-400'}`}>{icon}</span>
      <span className={`text-[10px] font-bold mt-1 uppercase ${active ? color : 'text-gray-400'}`}>{label}</span>
    </button>
  );
}

