// 6. Word Search - Updated to Batches, lowercase, and display words
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [batchIdx, setBatchIdx] = useState(0);
  const BATCH_SIZE = 5;
  const wordBatch = useMemo(() => VOCABULARY.slice(batchIdx * BATCH_SIZE, (batchIdx + 1) * BATCH_SIZE), [batchIdx]);

  const [grid, setGrid] = useState<string[][]>([]);
  const [found, setFound] = useState<string[]>([]);
  const [selectedCells, setSelectedCells] = useState<[number, number][]>([]);

  useEffect(() => {
    const size = 12;
    const newGrid = Array(size).fill(0).map(() => Array(size).fill(0).map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));

    wordBatch.forEach((w) => {
      const target = w.english.toLowerCase().replace(/[^a-z]/g, "");
      let placed = false;
      while (!placed) {
        const row = Math.floor(Math.random() * size);
        const colStart = Math.floor(Math.random() * (size - target.length));
        let overlap = false;
        for (let i = 0; i < target.length; i++) {
          if (newGrid[row][colStart + i].length > 1) { overlap = true; break; }
        }
        if (!overlap) {
          for (let i = 0; i < target.length; i++) {
            newGrid[row][colStart + i] = target[i] + "_"; // suffix to mark it's part of a word
          }
          placed = true;
        }
      }
    });
    setGrid(newGrid.map(row => row.map(cell => cell.charAt(0))));
    setFound([]);
    setSelectedCells([]);
  }, [wordBatch]);

  const handleCellClick = (r: number, c: number) => {
    const isSelected = selectedCells.some(([sr, sc]) => sr === r && sc === c);
    let newSelected;
    if (isSelected) {
      newSelected = selectedCells.filter(([sr, sc]) => !(sr === r && sc === c));
    } else {
      newSelected = [...selectedCells, [r, c] as [number, number]];
    }
    setSelectedCells(newSelected);

    const currentString = newSelected.map(([r, c]) => grid[r][c]).join("");
    const matchedWord = wordBatch.find(w => w.english.toLowerCase().replace(/[^a-z]/g, "") === currentString);

    if (matchedWord && !found.includes(matchedWord.english)) {
      const newFound = [...found, matchedWord.english];
      setFound(newFound);
      setSelectedCells([]);
      if (newFound.length === wordBatch.length) {
        if ((batchIdx + 1) * BATCH_SIZE < VOCABULARY.length) setBatchIdx(batchIdx + 1);
        else onWin();
      }
    }
  };

  return (
    <div className="p-6 bg-indigo-50 rounded-[2rem] border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex items-center gap-4 mb-6">
        <img src={getPokemonImageUrl(448)} className="w-20 h-20" alt="Lucario" />
        <h3 className="text-3xl font-title text-indigo-800">Word Search Batch {batchIdx + 1}</h3>
      </div>

      <div className="flex flex-wrap gap-2 mb-8 justify-center">
        {wordBatch.map(w => (
          <span key={w.id} className={`px-4 py-1 rounded-full border-2 font-bold transition-all ${found.includes(w.english) ? 'bg-green-100 border-green-500 text-green-700 line-through opacity-50' : 'bg-white border-indigo-200 text-indigo-600'}`}>
            {w.english.toLowerCase()}
          </span>
        ))}
      </div>

      <div className="grid grid-cols-12 gap-1 bg-white p-2 rounded-xl shadow-xl border-4 border-indigo-100">
        {grid.map((row, r) => row.map((char, c) => {
          const isSelected = selectedCells.some(([sr, sc]) => sr === r && sc === c);
          return (
            <button key={`${r}-${c}`} onClick={() => handleCellClick(r, c)} className={`w-7 h-7 sm:w-8 sm:h-8 text-lg font-bold rounded flex items-center justify-center transition-colors ${isSelected ? 'bg-indigo-500 text-white' : 'hover:bg-indigo-100'}`}>
              {char}
            </button>
          );
        }))}
      </div>
    </div>
  );
};

// Added PokemonBattle component to fix the error "Cannot find name 'PokemonBattle'"
const PokemonBattle = ({ onWin }: { onWin: () => void }) => {
  const [hp, setHp] = useState(100);
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx % VOCABULARY.length];
  const [feedback, setFeedback] = useState<'IDLE' | 'HIT' | 'MISS'>('IDLE');

  const options = useMemo(() => {
    const opts = [targetWord.chinese];
    while (opts.length < 3) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].chinese;
      if (!opts.includes(rand)) opts.push(rand);
    }
    return opts.sort(() => Math.random() - 0.5);
  }, [currentIdx, targetWord.chinese]);

  const handleAttack = (choice: string) => {
    if (choice === targetWord.chinese) {
      setFeedback('HIT');
      setHp(prev => Math.max(0, prev - 25));
      setTimeout(() => {
        setFeedback('IDLE');
        if (hp <= 25) {
          onWin();
        } else {
          setCurrentIdx(prev => prev + 1);
        }
      }, 600);
    } else {
      setFeedback('MISS');
      setTimeout(() => setFeedback('IDLE'), 600);
    }
  };

  return (
    <div className="p-8 bg-orange-50 min-h-[60vh] rounded-[3rem] border-4 border-orange-200 flex flex-col items-center">
      <div className="w-full max-w-2xl bg-white p-6 rounded-3xl shadow-xl border-4 border-orange-100 flex flex-col items-center relative overflow-hidden">
        {/* Opponent */}
        <div className="w-full flex justify-end mb-8">
          <div className="w-1/2">
             <div className="bg-gray-100 p-2 rounded-xl mb-2">
               <div className="flex justify-between font-bold text-xs mb-1"><span>MEWTWO</span><span>LV 99</span></div>
               <div className="h-2 bg-gray-300 rounded-full overflow-hidden">
                 <div className="h-full bg-green-500 transition-all duration-500" style={{ width: `${hp}%` }}></div>
               </div>
             </div>
             <img src={getPokemonImageUrl(150)} className={`w-32 h-32 ml-auto ${feedback === 'HIT' ? 'animate-bounce' : ''}`} alt="Mewtwo" />
          </div>
        </div>

        {/* Player */}
        <div className="w-full flex justify-start mb-8">
           <img src={getPokemonImageUrl(25)} className="w-32 h-32 pokemon-float" alt="Pikachu" />
        </div>

        <div className="w-full bg-gray-800 p-6 rounded-2xl text-white">
          <p className="text-xl font-bold mb-4">What does "{targetWord.english}" mean?</p>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {options.map(opt => (
              <button key={opt} onClick={() => handleAttack(opt)} className="bg-white/10 hover:bg-white/20 p-4 rounded-xl border-2 border-white/20 text-left font-bold transition-all">
                {opt}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

