          <NavBtn icon="🔍" label="Search" active={view === GameType.WORD_SEARCH} onClick={() => setView(GameType.WORD_SEARCH)} color="text-indigo-600" />
          <NavBtn icon="🔥" label="Battle" active={view === GameType.POKEMON_BATTLE} onClick={() => setView(GameType.POKEMON_BATTLE)} color="text-orange-600" />
          <NavBtn icon="🌧️" label="Rain" active={view === GameType.RAIN_GAME} onClick={() => setView(GameType.RAIN_GAME)} color="text-blue-700" />
          <NavBtn icon="🧠" label="Memory" active={view === GameType.MEMORY_GAME} onClick={() => setView(GameType.MEMORY_GAME)} color="text-purple-600" />
        </div>
      </nav>

      {reward && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center p-4 z-[100] backdrop-blur-sm">
          <div className="bg-white rounded-[4rem] p-10 max-w-sm w-full text-center shadow-2xl border-[12px] border-yellow-400">
            <img src={reward.imageUrl} className="w-56 h-56 mx-auto mb-6 pokemon-float" alt="Pokemon" />
            <h2 className="text-4xl font-title text-yellow-600 mb-2">GOTCHA! 🎉</h2>
            <p className="text-2xl font-bold text-gray-700 italic mb-8">You caught a {reward.name}!</p>
            <button onClick={() => setReward(null)} className="bg-green-500 text-white font-title text-xl py-4 px-10 rounded-full w-full shadow-lg">AWESOME!</button>
          </div>
        </div>
      )}
    </div>
  );
}

function NavBtn({ icon, label, active, onClick, color }: { icon: any, label: string, active: boolean, onClick: () => void, color: string }) {
  return (
    <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-2xl transition-all ${active ? 'bg-yellow-100 scale-110' : 'opacity-60 grayscale-[40%] hover:opacity-100'}`}>
      <span className={`text-2xl ${active ? color : 'text-gray-400'}`}>{icon}</span>
      <span className={`text-[10px] font-title mt-1 uppercase ${active ? color : 'text-gray-400'}`}>{label}</span>
    </button>
  );
}

