  const [filter, setFilter] = useState<string>('All');
  const [selectedWord, setSelectedWord] = useState<WordItem | null>(null);
  const [cardIdx, setCardIdx] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  const filteredVocab = useMemo(() => {
    if (filter === 'All') return VOCABULARY;
    return VOCABULARY.filter(w => w.category === filter);
  }, [filter]);

  useEffect(() => {
    let interval: any;
    if (mode === 'PLAY' && isPlaying) {
      interval = setInterval(() => {
        setCardIdx(prev => (prev + 1) % filteredVocab.length);
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [mode, isPlaying, filteredVocab]);

  return (
    <div className="p-4 max-w-4xl mx-auto pb-32">
      <div className="bg-white rounded-3xl p-6 shadow-xl border-4 border-yellow-400 mb-6 flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <div className="bg-yellow-100 p-3 rounded-full">
            <LucideCreditCard className="text-yellow-600" />
          </div>
          <h2 className="text-2xl font-title text-yellow-600">Diary Word Explorer</h2>
        </div>

        <div className="flex bg-gray-100 p-1 rounded-2xl border-2 border-gray-200">
          <button onClick={() => setMode('LIST')} className={`px-4 py-2 rounded-xl flex items-center gap-2 font-bold transition-all ${mode === 'LIST' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-400'}`}>
            <LucideList size={18} /> LIST
          </button>
          <button onClick={() => { setMode('CARDS'); setCardIdx(0); }} className={`px-4 py-2 rounded-xl flex items-center gap-2 font-bold transition-all ${mode === 'CARDS' ? 'bg-white shadow-sm text-pink-600' : 'text-gray-400'}`}>
            <LucideCreditCard size={18} /> CARDS
          </button>
          <button onClick={() => { setMode('PLAY'); setCardIdx(0); setIsPlaying(true); }} className={`px-4 py-2 rounded-xl flex items-center gap-2 font-bold transition-all ${mode === 'PLAY' ? 'bg-white shadow-sm text-green-600' : 'text-gray-400'}`}>
            <LucidePlay size={18} /> PLAY
          </button>
        </div>
      </div>

      <div className="flex gap-2 mb-6 overflow-x-auto pb-2 scrollbar-hide">
        {['All', 'Activities', 'Feelings', 'Time'].map(cat => (
          <button key={cat} onClick={() => { setFilter(cat); setCardIdx(0); }} className={`px-6 py-2 rounded-full border-2 font-bold whitespace-nowrap transition-all ${filter === cat ? 'bg-blue-500 border-blue-600 text-white' : 'bg-white border-gray-200 text-gray-500'}`}>
            {cat}
          </button>
        ))}
      </div>

      {mode === 'LIST' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filteredVocab.map((word) => (
            <div key={word.id} onClick={() => setSelectedWord(word)} className="bg-white p-5 rounded-3xl shadow-sm border-2 border-blue-50 flex items-center space-x-4 hover:border-yellow-400 hover:scale-[1.02] transition-all cursor-pointer group">
              <span className="text-5xl group-hover:scale-110 transition-transform">{word.emoji}</span>
              <div className="flex-1">
                <p className="text-2xl font-bold text-blue-600">{word.english}</p>
                <p className="text-xl text-gray-700 font-bold">{word.chinese}</p>
                <p className="text-sm text-gray-400 italic">{word.pronunciation}</p>
              </div>
              <LucideInfo className="text-gray-300" />
            </div>
          ))}
        </div>
      )}

      {(mode === 'CARDS' || mode === 'PLAY') && filteredVocab.length > 0 && (
        <div className="flex flex-col items-center">
          <div className="w-full max-w-lg aspect-[4/3] relative perspective-1000">
            <div className="w-full h-full bg-white rounded-[3rem] shadow-2xl border-8 border-yellow-400 flex flex-col items-center justify-center p-10 text-center relative overflow-hidden group" onClick={() => setSelectedWord(filteredVocab[cardIdx])}>
              <div className="absolute top-4 right-4 text-gray-300 font-title">{cardIdx + 1}/{filteredVocab.length}</div>
              <span className="text-9xl mb-6 animate-bounce">{filteredVocab[cardIdx].emoji}</span>
              <h3 className="text-5xl font-title text-blue-600 mb-2">{filteredVocab[cardIdx].english}</h3>
              <p className="text-3xl font-bold text-gray-600">{filteredVocab[cardIdx].chinese}</p>
              <p className="text-gray-400 mt-4 italic">{filteredVocab[cardIdx].pronunciation}</p>
              <div className="mt-8 bg-yellow-100 text-yellow-700 px-6 py-2 rounded-full font-bold flex items-center gap-2">
                <LucideSearch size={16} /> TAP TO EXPLORE
              </div>
            </div>
          </div>

          <div className="flex items-center gap-8 mt-10">
            {mode === 'CARDS' && (
              <>
                <button onClick={() => setCardIdx(prev => (prev - 1 + filteredVocab.length) % filteredVocab.length)} className="bg-blue-500 text-white p-4 rounded-full shadow-lg hover:scale-110 transition-transform">
                   <LucideRefreshCcw style={{ transform: 'scaleX(-1)' }} />
                </button>
                <button onClick={() => setCardIdx(prev => (prev + 1) % filteredVocab.length)} className="bg-blue-500 text-white p-4 rounded-full shadow-lg hover:scale-110 transition-transform">
                   <LucideRefreshCcw />
                </button>
              </>
            )}
            {mode === 'PLAY' && (
              <button onClick={() => setIsPlaying(!isPlaying)} className={`${isPlaying ? 'bg-red-500' : 'bg-green-500'} text-white p-6 rounded-full shadow-xl hover:scale-110 transition-transform`}>
                {isPlaying ? <LucideX size={32} /> : <LucidePlay size={32} />}
              </button>
            )}
          </div>
        </div>
      )}

      {selectedWord && <WordDetailModal word={selectedWord} onClose={() => setSelectedWord(null)} />}
    </div>
  );
};

