// 1. Emoji Detective (Psyduck) - Updated with Chinese display under emoji
const EmojiDetective = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const options = useMemo(() => {
    const opts = [targetWord.english];
    while (opts.length < 4) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
      if (!opts.includes(rand)) opts.push(rand);
    }
    return opts.sort(() => Math.random() - 0.5);
  }, [currentIdx]);

  const handleSelect = (choice: string) => {
    if (choice === targetWord.english) {
      if (currentIdx + 1 < VOCABULARY.length) setCurrentIdx(currentIdx + 1);
      else onWin();
    }
  };

  return (
    <div className="flex flex-col items-center p-8 bg-blue-50 min-h-[60vh] rounded-[3rem] border-4 border-blue-200">
      <img src={getPokemonImageUrl(54)} className="w-32 h-32 pokemon-float" alt="Psyduck" />
      <h3 className="text-3xl font-title text-blue-800 my-6">Matching Detective 🕵️</h3>
      <div className="bg-white p-8 rounded-3xl shadow-xl flex flex-col items-center mb-12 border-8 border-blue-100">
        <span className="text-9xl mb-2">{targetWord.emoji}</span>
        <span className="text-4xl font-bold text-blue-400">{targetWord.chinese}</span>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full max-w-xl">
        {options.map(opt => (
          <button key={opt} onClick={() => handleSelect(opt)} className="bg-white p-6 rounded-2xl border-4 border-blue-200 text-2xl font-bold text-blue-600 hover:bg-blue-100 hover:scale-105 transition-all shadow-md">{opt}</button>
        ))}
      </div>
    </div>
  );
};

const SpellingBee = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [input, setInput] = useState('');
  const targetWord = VOCABULARY[currentIdx];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.toLowerCase().trim() === targetWord.english.toLowerCase()) {
      if (currentIdx + 1 < VOCABULARY.length) {
        setCurrentIdx(currentIdx + 1);
        setInput('');
      } else {
        onWin();
      }
    }
  };

  return (
    <div className="flex flex-col items-center p-8 bg-yellow-50 min-h-[60vh] rounded-[3rem] border-4 border-yellow-200">
      <img src={getPokemonImageUrl(25)} className="w-32 h-32 pokemon-float" alt="Pikachu" />
      <h3 className="text-3xl font-title text-yellow-800 my-6">Spelling Bee 🐝</h3>
      <div className="bg-white p-8 rounded-3xl shadow-xl flex flex-col items-center mb-8 border-8 border-yellow-100 w-full max-w-md">
        <span className="text-8xl mb-2">{targetWord.emoji}</span>
        <span className="text-3xl font-bold text-gray-700">{targetWord.chinese}</span>
      </div>
      <form onSubmit={handleSubmit} className="w-full max-w-md">
        <input 
          autoFocus
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type the English word..."
          className="w-full p-6 rounded-2xl border-4 border-yellow-300 text-2xl font-bold text-center focus:border-yellow-500 outline-none transition-all shadow-inner"
        />
        <button type="submit" className="w-full mt-4 bg-yellow-500 text-white p-4 rounded-2xl font-bold text-xl hover:bg-yellow-600 transition-colors shadow-lg">CHECK</button>
      </form>
    </div>
  );
};

const BubblePop = ({ onWin }: { onWin: () => void }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx];
  const [bubbles, setBubbles] = useState<{ id: number, text: string, x: number, y: number }[]>([]);

  useEffect(() => {
    const generateBubbles = () => {
      const texts = [targetWord.english];
      while (texts.length < 5) {
        const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].english;
        if (!texts.includes(rand)) texts.push(rand);
      }
      setBubbles(texts.sort(() => Math.random() - 0.5).map((t, i) => ({
        id: i,
        text: t,
        x: Math.random() * 80 + 10,
        y: Math.random() * 60 + 20
      })));
    };
    generateBubbles();
  }, [currentIdx, targetWord.english]);

  const handlePop = (text: string) => {
    if (text === targetWord.english) {
      if (currentIdx + 1 < VOCABULARY.length) setCurrentIdx(currentIdx + 1);
      else onWin();
    }
  };

  return (
    <div className="relative h-[70vh] w-full bg-cyan-50 rounded-[3rem] border-4 border-cyan-200 overflow-hidden p-8 flex flex-col items-center">
      <div className="z-10 text-center">
        <h3 className="text-3xl font-title text-cyan-800 mb-2">Bubble Pop! 🫧</h3>
        <div className="bg-white/80 backdrop-blur px-8 py-4 rounded-2xl border-4 border-cyan-100 shadow-sm inline-block">
           <p className="text-xl font-bold text-gray-500 uppercase mb-1">Pop the bubble for:</p>
           <p className="text-4xl font-bold text-cyan-600">{targetWord.chinese} {targetWord.emoji}</p>
        </div>
      </div>

      <div className="absolute inset-0">
        {bubbles.map(b => (
          <button
            key={b.id}
            onClick={() => handlePop(b.text)}
            style={{ left: `${b.x}%`, top: `${b.y}%` }}
            className="absolute -translate-x-1/2 -translate-y-1/2 w-32 h-32 rounded-full bg-gradient-to-br from-cyan-200 to-cyan-400 border-4 border-white shadow-xl flex items-center justify-center text-center p-2 font-bold text-cyan-900 animate-pulse hover:scale-110 transition-transform active:scale-90"
          >
            {b.text}
          </button>
        ))}
      </div>
    </div>
  );
};

// 6. Word Search - Updated to Batches, lowercase, and display words to search
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [batchIdx, setBatchIdx] = useState(0);
  const BATCH_SIZE = 5;
  const wordBatch = useMemo(() => VOCABULARY.slice(batchIdx * BATCH_SIZE, (batchIdx + 1) * BATCH_SIZE), [batchIdx]);

  const [grid, setGrid] = useState<string[][]>([]);
  const [found, setFound] = useState<string[]>([]);
  const [selectedCells, setSelectedCells] = useState<[number, number][]>([]);

  useEffect(() => {
    const size = 12;
    // Pre-fill with random letters
    const newGrid = Array(size).fill(0).map(() => Array(size).fill(0).map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));

    // Attempt to place words in batch
    wordBatch.forEach((w) => {
      const target = w.english.toLowerCase().replace(/[^a-z]/g, "");
      let placed = false;
      let attempts = 0;
      while (!placed && attempts < 50) {
        attempts++;
        const row = Math.floor(Math.random() * size);
        const colStart = Math.floor(Math.random() * (size - target.length));
        let overlap = false;
        // Check for overlaps with already placed word letters
        for (let i = 0; i < target.length; i++) {
          if (newGrid[row][colStart + i].length > 1) { overlap = true; break; }
        }
        if (!overlap) {
          for (let i = 0; i < target.length; i++) {
            newGrid[row][colStart + i] = target[i] + "_"; // Suffix to mark a word letter
          }
          placed = true;
        }
      }
    });
    // Clean up markers
    setGrid(newGrid.map(row => row.map(cell => cell.charAt(0))));
    setFound([]);
    setSelectedCells([]);
  }, [wordBatch]);

  const handleCellClick = (r: number, c: number) => {
    const isAlreadySelected = selectedCells.some(([sr, sc]) => sr === r && sc === c);
    let newSelected;
    if (isAlreadySelected) {
      newSelected = selectedCells.filter(([sr, sc]) => !(sr === r && sc === c));
    } else {
      newSelected = [...selectedCells, [r, c] as [number, number]];
    }
    setSelectedCells(newSelected);

    const currentString = newSelected.map(([r, c]) => grid[r][c]).join("");
    const matchedWord = wordBatch.find(w => w.english.toLowerCase().replace(/[^a-z]/g, "") === currentString);

    if (matchedWord && !found.includes(matchedWord.english)) {
      const newFound = [...found, matchedWord.english];
      setFound(newFound);
      setSelectedCells([]);
      if (newFound.length === wordBatch.length) {
        if ((batchIdx + 1) * BATCH_SIZE < VOCABULARY.length) {
          setBatchIdx(batchIdx + 1);
        } else {
          onWin();
        }
      }
    }
  };

  return (
    <div className="p-6 bg-indigo-50 rounded-[2rem] border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex items-center gap-4 mb-6">
        <img src={getPokemonImageUrl(448)} className="w-20 h-20" alt="Lucario" />
        <h3 className="text-3xl font-title text-indigo-800">Word Search (Group {batchIdx + 1})</h3>
      </div>

      <div className="flex flex-wrap gap-2 mb-8 justify-center">
        {wordBatch.map(w => (
          <div key={w.id} className={`px-4 py-2 rounded-full border-2 font-bold transition-all shadow-sm ${found.includes(w.english) ? 'bg-green-100 border-green-500 text-green-700 line-through opacity-50' : 'bg-white border-indigo-200 text-indigo-600'}`}>
            {w.english.toLowerCase()}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-12 gap-1 bg-white p-3 rounded-2xl shadow-xl border-4 border-indigo-100">
        {grid.map((row, r) => row.map((char, c) => {
          const isSelected = selectedCells.some(([sr, sc]) => sr === r && sc === c);
          return (
            <button key={`${r}-${c}`} onClick={() => handleCellClick(r, c)} className={`w-7 h-7 sm:w-8 sm:h-8 text-lg font-bold rounded flex items-center justify-center transition-colors ${isSelected ? 'bg-indigo-500 text-white' : 'hover:bg-indigo-100'}`}>
              {char}
            </button>
          );
        }))}
      </div>
      <button onClick={() => setSelectedCells([])} className="mt-6 text-sm font-bold text-indigo-400 uppercase tracking-widest hover:text-indigo-600">Clear Selection</button>
    </div>
  );
};

const PokemonBattle = ({ onWin }: { onWin: () => void }) => {
  const [hp, setHp] = useState(100);
  const [currentIdx, setCurrentIdx] = useState(0);
  const targetWord = VOCABULARY[currentIdx % VOCABULARY.length];
  const [feedback, setFeedback] = useState<'IDLE' | 'HIT' | 'MISS'>('IDLE');

  const options = useMemo(() => {
    const opts = [targetWord.chinese];
    while (opts.length < 3) {
      const rand = VOCABULARY[Math.floor(Math.random() * VOCABULARY.length)].chinese;
      if (!opts.includes(rand)) opts.push(rand);
    }
    return opts.sort(() => Math.random() - 0.5);
  }, [currentIdx, targetWord.chinese]);

  const handleAttack = (choice: string) => {
    if (choice === targetWord.chinese) {
      setFeedback('HIT');
      setHp(prev => Math.max(0, prev - 25));
      setTimeout(() => {
        setFeedback('IDLE');
        if (hp <= 25) {
          onWin();
        } else {
          setCurrentIdx(prev => prev + 1);
        }
      }, 600);
    } else {
      setFeedback('MISS');
      setTimeout(() => setFeedback('IDLE'), 600);
    }
  };

  return (
    <div className="p-8 bg-orange-50 min-h-[60vh] rounded-[3rem] border-4 border-orange-200 flex flex-col items-center">
      <div className="w-full max-w-2xl bg-white p-6 rounded-3xl shadow-xl border-4 border-orange-100 flex flex-col items-center relative overflow-hidden">
        <div className="w-full flex justify-end mb-8">
          <div className="w-1/2">
             <div className="bg-gray-100 p-2 rounded-xl mb-2">
               <div className="flex justify-between font-bold text-xs mb-1"><span>MEWTWO</span><span>LV 99</span></div>
               <div className="h-2 bg-gray-300 rounded-full overflow-hidden">
                 <div className="h-full bg-green-500 transition-all duration-500" style={{ width: `${hp}%` }}></div>
               </div>
             </div>
             <img src={getPokemonImageUrl(150)} className={`w-32 h-32 ml-auto ${feedback === 'HIT' ? 'animate-bounce' : ''}`} alt="Mewtwo" />
          </div>
        </div>

        <div className="w-full flex justify-start mb-8">
           <img src={getPokemonImageUrl(25)} className="w-32 h-32 pokemon-float" alt="Pikachu" />
        </div>

        <div className="w-full bg-gray-800 p-6 rounded-2xl text-white">
          <p className="text-xl font-bold mb-4">What does "{targetWord.english}" mean?</p>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {options.map(opt => (
              <button key={opt} onClick={() => handleAttack(opt)} className="bg-white/10 hover:bg-white/20 p-4 rounded-xl border-2 border-white/20 text-left font-bold transition-all">
                {opt}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

