            <button onClick={() => setReward(null)} className="bg-green-500 text-white font-title text-xl py-4 px-10 rounded-full w-full shadow-lg">AWESOME!</button>
          </div>
        </div>
      )}
    </div>
  );
}

function NavBtn({ icon, label, active, onClick, color }: { icon: any, label: string, active: boolean, onClick: () => void, color: string }) {
  return (
    <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-2xl transition-all ${active ? 'bg-yellow-100 scale-110' : 'opacity-60 grayscale-[40%] hover:opacity-100'}`}>
      <span className={`text-2xl ${active ? color : 'text-gray-400'}`}>{icon}</span>
      <span className={`text-[10px] font-title mt-1 uppercase ${active ? color : 'text-gray-400'}`}>{label}</span>
    </button>
  );
}

