// --- Game: Word Search ---
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [batch, setBatch] = useState(0);
  const currentWords = useMemo(() => VOCABULARY.slice(batch * 5, (batch + 1) * 5), [batch]);
  const [grid, setGrid] = useState<string[][]>([]);
  const [found, setFound] = useState<string[]>([]);
  const [selected, setSelected] = useState<[number, number][]>([]);

  useEffect(() => {
    const size = 12;
    const g = Array(size).fill(0).map(() => Array(size).fill(0).map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));
    currentWords.forEach(w => {
      const s = w.english.toLowerCase().replace(/[^a-z]/g, "");
      let placed = false;
      while (!placed) {
        const r = Math.floor(Math.random() * size), c = Math.floor(Math.random() * (size - s.length));
        let free = true;
        for (let i = 0; i < s.length; i++) if (g[r][c+i].length > 1) free = false;
        if (free) { for (let i = 0; i < s.length; i++) g[r][c+i] = s[i] + "_"; placed = true; }
      }
    });
    setGrid(g.map(r => r.map(c => c[0])));
    setFound([]); setSelected([]);
  }, [currentWords]);

  const click = (r: number, c: number) => {
    const next = [...selected, [r, c] as [number, number]];
    setSelected(next);
    const word = next.map(([r, c]) => grid[r][c]).join("");
    const match = currentWords.find(w => w.english.toLowerCase().replace(/[^a-z]/g, "") === word);
    if (match && !found.includes(match.english)) {
      const nextFound = [...found, match.english];
      setFound(nextFound); setSelected([]);
      if (nextFound.length === currentWords.length) {
        if ((batch + 1) * 5 < VOCABULARY.length) setBatch(batch + 1);
        else onWin();
      }
    } else if (next.length > 15) setSelected([]);
  };

  return (
    <div className="p-8 bg-indigo-50 rounded-[3rem] border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex flex-wrap gap-2 mb-8 justify-center">
        {currentWords.map(w => <span key={w.id} className={`px-4 py-1 rounded-full border-2 font-bold ${found.includes(w.english) ? 'bg-green-100 border-green-500 text-green-700 line-through' : 'bg-white border-indigo-200 text-indigo-600'}`}>{w.english.toLowerCase()}</span>)}
      </div>
      <div className="grid grid-cols-12 gap-1 bg-white p-2 rounded-xl border-4 border-indigo-100 shadow-xl">
        {grid.map((row, r) => row.map((char, c) => (
          <button key={`${r}-${c}`} onClick={() => click(r, c)} className={`w-7 h-7 sm:w-8 sm:h-8 text-lg font-bold rounded flex items-center justify-center ${selected.some(([sr, sc]) => sr === r && sc === c) ? 'bg-indigo-500 text-white' : 'hover:bg-indigo-100'}`}>{char}</button>
        )))}
      </div>
      <img src={getPokemonImageUrl(448)} className="w-24 h-24 mt-6" alt="Lucario"/>
    </div>
  );
};

// --- Game: Pokemon Battle ---
