            <div className="h-3 w-full bg-gray-200 rounded-full mt-2 overflow-hidden"><div className="h-full bg-green-500 transition-all duration-500" style={{ width: `${hp}%` }}/></div>
          </div>
          <img src={getPokemonImageUrl(150)} className="w-40 h-40 pokemon-float" alt="Mewtwo"/>
