// --- Game: Word Search (Fixed Crash) ---
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [batch, setBatch] = useState(0);
  const currentWords = useMemo(() => VOCABULARY.slice(batch * 5, (batch + 1) * 5), [batch]);
  const [grid, setGrid] = useState<string[][]>([]);
  const [found, setFound] = useState<string[]>([]);
  const [selected, setSelected] = useState<[number, number][]>([]);

  useEffect(() => {
    // Large enough size for longest word (21 chars)
    const size = 25;
    const g = Array(size).fill(null).map(() => Array(size).fill('').map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));

    currentWords.forEach(w => {
      const s = w.english.toLowerCase().replace(/[^a-z]/g, "");
      let placed = false;
      let attempts = 0;
      while (!placed && attempts < 100) {
        attempts++;
        const r = Math.floor(Math.random() * size);
        const c = Math.floor(Math.random() * (size - s.length));
        let free = true;
        for (let i = 0; i < s.length; i++) {
          // Check if cell is already marked by a suffix
          if (g[r][c+i].length > 1) free = false;
        }
        if (free) {
          for (let i = 0; i < s.length; i++) {
            g[r][c+i] = s[i] + "_"; 
          }
          placed = true;
        }
      }
    });

    // Clean data by stripping markers for display
    setGrid(g.map(row => row.map(cell => cell[0])));
    setFound([]); setSelected([]);
  }, [currentWords]);

  const click = (r: number, c: number) => {
    const next = [...selected, [r, c] as [number, number]];
    setSelected(next);
    const word = next.map(([r, c]) => grid[r][c]).join("");
    const match = currentWords.find(w => w.english.toLowerCase().replace(/[^a-z]/g, "") === word);
    if (match && !found.includes(match.english)) {
      const nextFound = [...found, match.english];
      setFound(nextFound); setSelected([]);
      if (nextFound.length === currentWords.length) {
        if ((batch + 1) * 5 < VOCABULARY.length) setBatch(batch + 1);
        else onWin();
      }
    } else if (next.length > 25) setSelected([]);
  };

  return (
    <div className="p-8 bg-indigo-50 rounded-[3rem] border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex flex-wrap gap-2 mb-8 justify-center">
        {currentWords.map(w => (
          <span key={w.id} className={`px-4 py-1 rounded-full border-2 font-bold transition-all ${found.includes(w.english) ? 'bg-green-100 border-green-500 text-green-700 line-through' : 'bg-white border-indigo-200 text-indigo-600'}`}>
            {w.english.toLowerCase()}
          </span>
        ))}
      </div>
      <div className="grid grid-cols-[repeat(25,minmax(0,1fr))] gap-1 bg-white p-2 rounded-xl border-2 border-indigo-100 shadow-xl overflow-x-auto w-full">
        {grid.map((row, r) => row.map((char, c) => (
          <button key={`${r}-${c}`} onClick={() => click(r, c)} className={`aspect-square min-w-[20px] text-xs font-bold rounded flex items-center justify-center transition-colors ${selected.some(([sr, sc]) => sr === r && sc === c) ? 'bg-indigo-500 text-white' : 'hover:bg-indigo-100'}`}>
            {char}
          </button>
        )))}
      </div>
      <div className="flex items-center gap-4 mt-8">
        <img src={getPokemonImageUrl(448)} className="w-20 h-20" alt="Lucario"/>
        <button onClick={() => setSelected([])} className="bg-indigo-100 text-indigo-600 px-6 py-2 rounded-full font-bold">CLEAR</button>
      </div>
    </div>
  );
};

// --- Game: Pokemon Battle ---
const PokemonBattle = ({ onWin }: { onWin: () => void }) => {
  const [hp, setHp] = useState(100);
  const [idx, setIdx] = useState(0);
  const target = VOCABULARY[idx % VOCABULARY.length];
  const options = useMemo(() => [target.chinese, ...VOCABULARY.filter(w => w.id !== target.id).sort(() => Math.random() - 0.5).slice(0, 3).map(w => w.chinese)].sort(() => Math.random() - 0.5), [idx]);

  const attack = (o: string) => {
    if (o === target.chinese) {
      setHp(h => Math.max(0, h - 25));
      if (hp <= 25) onWin();
      else setIdx(i => i + 1);
    }
  };

  return (
    <div className="p-8 bg-orange-100 rounded-[3rem] border-4 border-orange-200 min-h-[60vh] flex flex-col items-center justify-center">
      <div className="w-full max-w-2xl flex flex-col gap-10">
