// --- Game: Word Search (Fixed Crash) ---
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [batch, setBatch] = useState(0);
  const currentWords = useMemo(() => VOCABULARY.slice(batch * 5, (batch + 1) * 5), [batch]);
  const [grid, setGrid] = useState<string[][]>([]);
  const [found, setFound] = useState<string[]>([]);
  const [selected, setSelected] = useState<[number, number][]>([]);

  useEffect(() => {
    // Increase size to accommodate long words (max 21 chars)
    const size = 25;
    const g = Array(size).fill(null).map(() => Array(size).fill('').map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));

    currentWords.forEach(w => {
      const s = w.english.toLowerCase().replace(/[^a-z]/g, "");
      let placed = false;
      let attempts = 0;
      while (!placed && attempts < 100) {
        attempts++;
        const r = Math.floor(Math.random() * size);
        const c = Math.floor(Math.random() * (size - s.length));

        // Ensure c is within valid bounds
        if (c < 0) continue;

        let free = true;
        for (let i = 0; i < s.length; i++) {
          // Check if cell is already marked by a word (using suffix)
          if (g[r][c+i] && g[r][c+i].length > 1) {
            free = false;
            break;
          }
        }
        if (free) {
          for (let i = 0; i < s.length; i++) {
            g[r][c+i] = s[i] + "_"; // suffix to track word letters
          }
          placed = true;
        }
      }
    });

    // Clean suffix for display
    setGrid(g.map(row => row.map(cell => cell.charAt(0))));
    setFound([]); setSelected([]);
  }, [currentWords]);

  const click = (r: number, c: number) => {
    const next = [...selected, [r, c] as [number, number]];
    setSelected(next);
    const word = next.map(([r, c]) => grid[r][c]).join("");
    const match = currentWords.find(w => w.english.toLowerCase().replace(/[^a-z]/g, "") === word);
    if (match && !found.includes(match.english)) {
      const nextFound = [...found, match.english];
      setFound(nextFound); setSelected([]);
      if (nextFound.length === currentWords.length) {
        if ((batch + 1) * 5 < VOCABULARY.length) setBatch(batch + 1);
        else onWin();
      }
    } else if (next.length > 25) setSelected([]);
  };

  return (
    <div className="p-8 bg-indigo-50 rounded-[3rem] border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex flex-wrap gap-2 mb-8 justify-center">
        {currentWords.map(w => (
          <span key={w.id} className={`px-4 py-1 rounded-full border-2 font-bold transition-all ${found.includes(w.english) ? 'bg-green-100 border-green-500 text-green-700 line-through opacity-50' : 'bg-white border-indigo-200 text-indigo-600'}`}>
            {w.english.toLowerCase()}
          </span>
        ))}
      </div>
      <div className="grid grid-cols-[repeat(25,minmax(0,1fr))] gap-1 bg-white p-2 rounded-xl border-2 border-indigo-100 shadow-xl overflow-x-auto w-full">
        {grid.map((row, r) => row.map((char, c) => (
          <button key={`${r}-${c}`} onClick={() => click(r, c)} className={`aspect-square min-w-[18px] text-[10px] font-bold rounded flex items-center justify-center transition-colors ${selected.some(([sr, sc]) => sr === r && sc === c) ? 'bg-indigo-500 text-white' : 'hover:bg-indigo-100'}`}>
            {char}
          </button>
        )))}
      </div>
      <div className="flex items-center gap-4 mt-8">
        <img src={getPokemonImageUrl(448)} className="w-20 h-20" alt="Lucario"/>
        <button onClick={() => setSelected([])} className="bg-indigo-100 text-indigo-600 px-6 py-2 rounded-full font-bold shadow-md hover:bg-indigo-200 transition-all">CLEAR</button>
      </div>
    </div>
  );
};

