const PokemonBattle = ({ onWin }: { onWin: () => void }) => {
  const [hp, setHp] = useState(100);
  const [idx, setIdx] = useState(0);
  const target = VOCABULARY[idx % VOCABULARY.length];
  const options = useMemo(() => [target.chinese, ...VOCABULARY.filter(w => w.id !== target.id).sort(() => Math.random() - 0.5).slice(0, 3).map(w => w.chinese)].sort(() => Math.random() - 0.5), [idx]);

  const attack = (o: string) => {
    if (o === target.chinese) {
      setHp(h => Math.max(0, h - 25));
      if (hp <= 25) onWin();
      else setIdx(i => i + 1);
    }
  };

  return (
    <div className="p-8 bg-orange-100 rounded-[3rem] border-4 border-orange-200 min-h-[60vh] flex flex-col items-center justify-center">
      <div className="w-full max-w-2xl flex flex-col gap-10">
        <div className="flex justify-end gap-4 items-center">
          <div className="bg-white p-4 rounded-3xl border-2 border-gray-200 shadow-md w-48">
            <p className="font-title text-sm">MEWTWO <span className="text-gray-400">Lv.99</span></p>
            <div className="h-3 w-full bg-gray-200 rounded-full mt-2 overflow-hidden">
              <div className="h-full bg-green-500 transition-all duration-500" style={{ width: `${hp}%` }}/>
            </div>
          </div>
          <img src={getPokemonImageUrl(150)} className="w-40 h-40 pokemon-float" alt="Mewtwo"/>
        </div>
        <div className="flex justify-start gap-4 items-center">
          <img src={getPokemonImageUrl(6)} className="w-40 h-40 pokemon-float scale-x-[-1]" alt="Charizard"/>
          <div className="bg-gray-800 p-6 rounded-3xl text-white shadow-2xl flex-1">
            <p className="text-xl font-bold mb-4 italic">What is "{target.english}"?</p>
            <div className="grid grid-cols-2 gap-3">
              {options.map(o => <button key={o} onClick={() => attack(o)} className="bg-white/10 p-3 rounded-xl border border-white/20 font-bold hover:bg-white/20 transition-colors">{o}</button>)}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Game: Rain Game ---
const RainGame = ({ onWin }: { onWin: () => void }) => {
  const [idx, setIdx] = useState(0);
  const target = VOCABULARY[idx];
  const drops = useMemo(() => [target.english, ...VOCABULARY.filter(w => w.id !== target.id).sort(() => Math.random() - 0.5).slice(0, 5).map(w => w.english)].sort(() => Math.random() - 0.5).map((t, i) => ({ text: t, left: 10 + (i * 15), delay: i * 0.5 })), [idx]);

  const select = (o: string) => {
    if (o === target.english) {
      if (idx + 1 < VOCABULARY.length) setIdx(idx + 1);
      else onWin();
    }
  };

  return (
    <div className="bg-blue-200 rounded-[3rem] p-10 min-h-[60vh] relative overflow-hidden flex flex-col items-center">
      <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/rain.png')] opacity-20 pointer-events-none animate-[pulse_2s_infinite]"/>
      <h3 className="text-3xl font-title text-blue-800 mb-6 z-10">Catch the Water! 🌧️</h3>
      <div className="bg-white px-8 py-3 rounded-full border-4 border-blue-400 text-3xl font-bold mb-10 shadow-xl z-10">{target.chinese}</div>
      <div className="flex-1 w-full relative">
        {drops.map((d, i) => (
          <button key={i} onClick={() => select(d.text)} style={{ left: `${d.left}%`, top: `${20 + (i * 10)}%` }} className="absolute bg-blue-500/80 text-white p-4 rounded-full font-bold shadow-lg border-2 border-white hover:scale-110 active:scale-95 bubble-float transition-all">
            💧 {d.text}
          </button>
        ))}
      </div>
      <img src={getPokemonImageUrl(186)} className="absolute bottom-4 left-4 w-32 h-32 pokemon-float" alt="Politoed"/>
    </div>
  );
};

// --- Game: Memory Game ---
const MemoryGame = ({ onWin }: { onWin: () => void }) => {
  const [phase, setPhase] = useState<'study' | 'guess'>('study');
  const [subset, setSubset] = useState<WordItem[]>([]);
  const [missing, setMissing] = useState<WordItem | null>(null);
  const [timer, setTimer] = useState(10);

  useEffect(() => {
    const s = VOCABULARY.sort(() => Math.random() - 0.5).slice(0, 8);
    setSubset(s); setMissing(s[Math.floor(Math.random()*8)]); setPhase('study'); setTimer(10);
  }, []);

  useEffect(() => {
    if (phase === 'study' && timer > 0) {
      const t = setTimeout(() => setTimer(timer - 1), 1000);
      return () => clearTimeout(t);
    } else if (phase === 'study') setPhase('guess');
  }, [timer, phase]);

  return (
    <div className="p-8 bg-purple-50 rounded-[3rem] border-4 border-purple-200 min-h-[60vh] flex flex-col items-center">
      <img src={getPokemonImageUrl(151)} className="w-24 h-24 mb-6 pokemon-float" alt="Mew"/>
      {phase === 'study' ? (
        <>
          <h3 className="text-3xl font-title text-purple-700 mb-2">Memory Time! 🧠</h3>
          <div className="text-5xl font-bold text-red-500 mb-10">{timer}s</div>
          <div className="grid grid-cols-4 gap-4">
            {subset.map(w => (
              <div key={w.id} className="bg-white p-3 rounded-xl shadow-md border-2 border-purple-100 flex flex-col items-center transition-all">
                <span className="text-3xl">{w.emoji}</span>
                <p className="text-[10px] font-bold text-center">{w.english}</p>
              </div>
            ))}
          </div>
        </>
      ) : (
        <>
          <h3 className="text-3xl font-title text-purple-700 mb-8">Who is missing? 🤔</h3>
          <div className="grid grid-cols-4 gap-4 mb-10 opacity-40">
            {subset.filter(w => w.id !== missing?.id).map(w => (
              <div key={w.id} className="bg-white p-3 rounded-xl border-2 border-purple-100 flex flex-col items-center">
                <span className="text-3xl">{w.emoji}</span>
              </div>
            ))}
            <div className="bg-purple-200 p-3 rounded-xl flex items-center justify-center text-4xl animate-pulse">❓</div>
          </div>
          <div className="grid grid-cols-2 gap-3 w-full max-w-lg">
            {subset.sort(() => Math.random() - 0.5).map(w => (
              <button key={w.id} onClick={() => w.id === missing?.id ? onWin() : setPhase('study')} className="bg-white p-4 rounded-xl border-2 border-purple-300 font-bold hover:bg-purple-100 shadow-sm transition-all active:scale-95">
                {w.english}
              </button>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

