// --- Game: Word Search ---
const WordSearch = ({ onWin }: { onWin: () => void }) => {
  const [batch, setBatch] = useState(0);
  const currentWords = useMemo(() => VOCABULARY.slice(batch * 4, (batch + 1) * 4), [batch]);
  const [grid, setGrid] = useState<string[][]>([]);
  const [found, setFound] = useState<string[]>([]);
  const [selected, setSelected] = useState<[number, number][]>([]);

  useEffect(() => {
    // Reduced size to make it easier for kids (10x10)
    const size = 12;
    const g = Array(size).fill(null).map(() => Array(size).fill('').map(() => String.fromCharCode(97 + Math.floor(Math.random() * 26))));

    currentWords.forEach(w => {
      // Clean word: take first 10 characters or only use short words to avoid crash
      const s = w.english.toLowerCase().replace(/[^a-z]/g, "").substring(0, size);

      let placed = false;
      let attempts = 0;
      while (!placed && attempts < 100) {
        attempts++;
        const r = Math.floor(Math.random() * size);
        const maxCol = size - s.length;
        const c = Math.floor(Math.random() * (maxCol + 1));

        if (c < 0) continue;

        let free = true;
        for (let i = 0; i < s.length; i++) {
          const cell = g[r][c + i];
          if (cell && cell.length > 1) {
            free = false;
            break;
          }
        }
        if (free) {
          for (let i = 0; i < s.length; i++) {
            g[r][c + i] = s[i] + "_"; 
          }
          placed = true;
        }
      }
    });

    setGrid(g.map(row => row.map(cell => cell.charAt(0))));
    setFound([]); setSelected([]);
  }, [currentWords]);

  const click = (r: number, c: number) => {
    const isAlreadySelected = selected.some(([sr, sc]) => sr === r && sc === c);
    let next: [number, number][];

    if (isAlreadySelected) {
      next = selected.filter(([sr, sc]) => !(sr === r && sc === c));
    } else {
      next = [...selected, [r, c] as [number, number]];
    }

    setSelected(next);
    const word = next.map(([r, c]) => grid[r][c]).join("");

    // Check if word starts with or matches any in currentWords
    const match = currentWords.find(w => {
      const clean = w.english.toLowerCase().replace(/[^a-z]/g, "");
      // If word exceeds board size, we only matched what we placed (the substring)
      const target = clean.substring(0, 12);
      return target === word;
    });

    if (match && !found.includes(match.english)) {
      const nextFound = [...found, match.english];
      setFound(nextFound); setSelected([]);
      if (nextFound.length === currentWords.length) {
        if ((batch + 1) * 4 < VOCABULARY.length) setBatch(batch + 1);
        else onWin();
      }
    } else if (next.length > 12) {
      setSelected([]);
    }
  };

  return (
    <div className="p-8 bg-indigo-50 rounded-[3rem] border-4 border-indigo-200 flex flex-col items-center">
      <div className="flex flex-wrap gap-2 mb-8 justify-center">
        {currentWords.map(w => (
          <span key={w.id} className={`px-4 py-1 rounded-full border-2 font-bold transition-all ${found.includes(w.english) ? 'bg-green-100 border-green-500 text-green-700 line-through opacity-50' : 'bg-white border-indigo-200 text-indigo-600'}`}>
            {w.english.toLowerCase().substring(0, 12)}
          </span>
        ))}
      </div>
      <div className="grid grid-cols-[repeat(12,minmax(0,1fr))] gap-2 bg-white p-4 rounded-3xl border-4 border-indigo-100 shadow-xl overflow-hidden w-full max-w-md mx-auto">
        {grid.map((row, r) => row.map((char, c) => (
          <button key={`${r}-${c}`} onClick={() => click(r, c)} className={`aspect-square min-w-[30px] text-xl font-bold rounded-lg flex items-center justify-center transition-colors ${selected.some(([sr, sc]) => sr === r && sc === c) ? 'bg-indigo-500 text-white' : 'bg-indigo-50/30 hover:bg-indigo-100'}`}>
            {char}
          </button>
        )))}
      </div>
      <div className="flex items-center gap-6 mt-10">
        <img src={getPokemonImageUrl(448)} className="w-24 h-24 pokemon-float" alt="Lucario"/>
        <button onClick={() => setSelected([])} className="bg-indigo-500 text-white px-8 py-3 rounded-full font-bold shadow-lg hover:bg-indigo-600 transition-all active:scale-95 uppercase">Clear Selection</button>
      </div>
    </div>
  );
};

// --- Game: Memory Game ---
const MemoryGame = ({ onWin }: { onWin: () => void }) => {
  const [phase, setPhase] = useState<'study' | 'guess'>('study');
  const [subset, setSubset] = useState<WordItem[]>([]);
  const [missing, setMissing] = useState<WordItem | null>(null);
  const [timer, setTimer] = useState(10);

  useEffect(() => {
    const s = VOCABULARY.sort(() => Math.random() - 0.5).slice(0, 8);
    setSubset(s); setMissing(s[Math.floor(Math.random()*8)]); setPhase('study'); setTimer(10);
  }, []);

  useEffect(() => {
    if (phase === 'study' && timer > 0) {
      const t = setTimeout(() => setTimer(timer - 1), 1000);
      return () => clearTimeout(t);
    } else if (phase === 'study') setPhase('guess');
  }, [timer, phase]);

  return (
    <div className="p-8 bg-purple-50 rounded-[3rem] border-4 border-purple-200 min-h-[60vh] flex flex-col items-center">
      <img src={getPokemonImageUrl(151)} className="w-24 h-24 mb-6 pokemon-float" alt="Mew"/>
      {phase === 'study' ? (
        <>
          <h3 className="text-3xl font-title text-purple-700 mb-2">Memory Time! 🧠</h3>
          <div className="text-5xl font-bold text-red-500 mb-10">{timer}s</div>
          <div className="grid grid-cols-4 gap-4">
            {subset.map(w => (
              <div key={w.id} className="bg-white p-3 rounded-xl shadow-md border-2 border-purple-100 flex flex-col items-center transition-all">
                <span className="text-4xl">{w.emoji}</span>
                <p className="text-[12px] font-bold text-center mt-2">{w.english}</p>
              </div>
            ))}
          </div>
        </>
      ) : (
        <>
          <h3 className="text-3xl font-title text-purple-700 mb-8">Who is missing? 🤔</h3>
          <div className="grid grid-cols-4 gap-4 mb-10 opacity-40">
            {subset.filter(w => w.id !== missing?.id).map(w => (
              <div key={w.id} className="bg-white p-3 rounded-xl border-2 border-purple-100 flex flex-col items-center">
                <span className="text-4xl">{w.emoji}</span>
              </div>
            ))}
            <div className="bg-purple-200 p-3 rounded-xl flex items-center justify-center text-5xl animate-pulse">❓</div>
          </div>
          <div className="grid grid-cols-2 gap-3 w-full max-w-lg">
            {subset.sort(() => Math.random() - 0.5).map(w => (
              <button key={w.id} onClick={() => w.id === missing?.id ? onWin() : setPhase('study')} className="bg-white p-6 rounded-2xl border-4 border-purple-300 font-bold hover:bg-purple-100 shadow-sm transition-all active:scale-95 text-xl">
                {w.english}
              </button>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

