// --- Game: Bubble Pop (Fixed Grid) ---
const BubblePop = ({ onWin }: { onWin: () => void }) => {
  const [idx, setIdx] = useState(0);
  const target = VOCABULARY[idx];
  const [caughtCount, setCaughtCount] = useState(0);
