// --- Game: Tug of War ---
const TugOfWarGame = ({ onWin }: { onWin: (winner: string) => void }) => {
  const [qIdx, setQIdx] = useState(0);
  const [score, setScore] = useState(0); // -3 to 3 (Left player to Right player)
  const [gameOver, setGameOver] = useState(false);

  const questionPool = useMemo(() => VOCABULARY.sort(() => Math.random() - 0.5).slice(0, 5), []);
  const currentTarget = questionPool[qIdx];

  const options = useMemo(() => {
    if (!currentTarget) return [];
    const others = VOCABULARY.filter(w => w.id !== currentTarget.id).sort(() => Math.random() - 0.5).slice(0, 3);
    return [currentTarget, ...others].sort(() => Math.random() - 0.5);
  }, [currentTarget]);

  const handleSelect = (side: 'L' | 'R', english: string) => {
    if (gameOver) return;

    if (english === currentTarget.english) {
      playSound('correct');
      const newScore = side === 'L' ? score - 1 : score + 1;
      setScore(newScore);

      if (Math.abs(newScore) >= 3 || qIdx === 4) {
        setGameOver(true);
        setTimeout(() => onWin(newScore < 0 ? 'Player Left' : 'Player Right'), 1000);
      } else {
        setQIdx(qIdx + 1);
      }
    } else {
      playSound('wrong');
    }
  };

  if (!currentTarget) return null;

  return (
    <div className="fixed inset-0 bg-orange-50 z-[100] flex flex-col md:flex-row overflow-hidden">
      {/* Player Left (Pikachu) */}
      <div className="flex-1 flex flex-col items-center justify-center p-8 border-b-4 md:border-b-0 md:border-r-4 border-orange-200 bg-blue-50/50">
        <div className="mb-8 text-center">
          <img src={getPokemonImageUrl(25)} className="w-24 h-24 mb-4 pokemon-float" alt="Pikachu" />
          <h2 className="text-3xl font-bold text-blue-600">Player 1 ⚡</h2>
          <div className="mt-4 text-4xl font-black text-gray-700">{currentTarget.chinese}</div>
        </div>
        <div className="grid grid-cols-2 gap-4 w-full max-w-md">
          {options.map(opt => (
            <button key={`L-${opt.id}`} onClick={() => handleSelect('L', opt.english)} className="bg-white p-4 rounded-2xl border-4 border-blue-200 shadow-md text-xl font-bold text-blue-800 active:scale-95 transition-all">
              {opt.english}
            </button>
          ))}
        </div>
      </div>

      {/* The Rope Center */}
      <div className="absolute top-1/2 left-0 right-0 md:top-0 md:bottom-0 md:left-1/2 -translate-y-1/2 md:-translate-y-0 md:-translate-x-1/2 flex items-center justify-center pointer-events-none z-10">
        <div className="relative w-full h-8 md:w-8 md:h-full flex items-center justify-center">
            {/* Visual Rope */}
            <div className="absolute w-full h-2 md:w-2 md:h-full bg-orange-800 rounded-full shadow-lg border-2 border-orange-950"></div>
            {/* Moving Knot */}
            <div 
                className="absolute w-12 h-12 bg-red-500 rounded-full shadow-xl border-4 border-white transition-all duration-500 flex items-center justify-center"
                style={{
                    left: `${50 + (score * 15)}%`,
                    top: '50%',
                    transform: 'translate(-50%, -50%)'
                }}
            >
                <div className="text-2xl">🎀</div>
            </div>
        </div>
      </div>

      {/* Player Right (Charmander) */}
      <div className="flex-1 flex flex-col items-center justify-center p-8 bg-red-50/50">
        <div className="mb-8 text-center">
          <img src={getPokemonImageUrl(4)} className="w-24 h-24 mb-4 pokemon-float" alt="Charmander" />
          <h2 className="text-3xl font-bold text-red-600">Player 2 🔥</h2>
          <div className="mt-4 text-4xl font-black text-gray-700">{currentTarget.chinese}</div>
        </div>
        <div className="grid grid-cols-2 gap-4 w-full max-w-md">
          {options.map(opt => (
            <button key={`R-${opt.id}`} onClick={() => handleSelect('R', opt.english)} className="bg-white p-4 rounded-2xl border-4 border-red-200 shadow-md text-xl font-bold text-red-800 active:scale-95 transition-all">
              {opt.english}
            </button>
          ))}
        </div>
      </div>

      <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-white/80 px-8 py-2 rounded-full shadow-lg text-2xl font-black text-orange-600">
        Q {qIdx + 1} / 5
      </div>
    </div>
  );
};

